import{_ as r,o,c as e,a2 as i}from"./chunks/framework.DnrXFDHb.js";const n="/images/dashboard-cargo.png",s="/images/tombol-add-new.png",l="/images/add-new-cargo.png",d="/images/tombol-edit.png",g="/images/tombol-hapus.png",t="/images/tombol-hapus-masal.png",m="/images/tombol-export-xls.png",c="/images/tombol-synch-api.png",h="/images/tombol-remove-duplicate.png",u="/images/tombol-remove-blank.png",A=JSON.parse('{"title":"Input Data Manifest (Cargo)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/input-data.md","filePath":"guide/input-data.md"}'),p={name:"guide/input-data.md"};function b(k,a,x,_,f,D){return o(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="input-data-manifest-cargo" tabindex="-1">Input Data Manifest (Cargo) <a class="header-anchor" href="#input-data-manifest-cargo" aria-label="Permalink to &quot;Input Data Manifest (Cargo)&quot;">​</a></h1><p>Halaman <strong>Data Cargo</strong> adalah halaman utama setelah login. Digunakan untuk mengelola data manifest kargo.</p><h2 id="ringkasan-dashboard" tabindex="-1">Ringkasan Dashboard <a class="header-anchor" href="#ringkasan-dashboard" aria-label="Permalink to &quot;Ringkasan Dashboard&quot;">​</a></h2><img src="'+n+'" alt="dashboard" width="800"><p>Empat kartu ringkasan menampilkan statistik:</p><table tabindex="0"><thead><tr><th>Kartu</th><th>Deskripsi</th></tr></thead><tbody><tr><td><strong>Total MAWB</strong></td><td>Jumlah Master Air Waybill unik</td></tr><tr><td><strong>Total HAWB</strong></td><td>Jumlah House Air Waybill unik</td></tr><tr><td><strong>Incomplete Scan</strong></td><td>Jumlah kargo yang belum selesai discan</td></tr><tr><td><strong>Complete Scan</strong></td><td>Jumlah kargo yang sudah selesai discan seluruhnya</td></tr></tbody></table><h2 id="menambah-data-cargo" tabindex="-1">Menambah Data Cargo <a class="header-anchor" href="#menambah-data-cargo" aria-label="Permalink to &quot;Menambah Data Cargo&quot;">​</a></h2><ol><li>Klik tombol <img src="'+s+'" width="100"></li><li>Isi data pada form berikut:</li></ol><img src="'+l+'" width="500"><ul><li><strong>ULD No</strong> — Nomor Unit Load Device</li><li><strong>MAWB</strong> (wajib) — Master Air Waybill</li><li><strong>HAWB</strong> — House Air Waybill</li><li><strong>Tot Pcs</strong> — Jumlah piece yang dideklarasikan</li><li><strong>Tot Weight</strong> — Berat total (kg)</li><li><strong>Goods Desc</strong> — Deskripsi barang</li></ul><ol start="3"><li>Klik <strong>Save Cargo</strong></li></ol><h2 id="mengedit-data-cargo" tabindex="-1">Mengedit Data Cargo <a class="header-anchor" href="#mengedit-data-cargo" aria-label="Permalink to &quot;Mengedit Data Cargo&quot;">​</a></h2><p>Klik ikon <strong>Edit</strong> <img src="'+d+'" width="50"> pada baris cargo yang ingin diubah. Konfirmasi dengan password untuk menyimpan perubahan.</p><h2 id="menghapus-data-cargo" tabindex="-1">Menghapus Data Cargo <a class="header-anchor" href="#menghapus-data-cargo" aria-label="Permalink to &quot;Menghapus Data Cargo&quot;">​</a></h2><ul><li><strong>Hapus satu:</strong> Klik ikon <strong>Hapus (trash)</strong> <img src="'+g+'" width="50"> pada baris cargo</li><li><strong>Hapus massal:</strong> Centang beberapa baris, lalu klik <strong>Delete Selected</strong> <img src="'+t+'" width="200"></li><li>Semua penghapusan memerlukan konfirmasi password</li></ul><h2 id="import-data-dari-excel" tabindex="-1">Import Data dari Excel <a class="header-anchor" href="#import-data-dari-excel" aria-label="Permalink to &quot;Import Data dari Excel&quot;">​</a></h2><ol><li>Klik tombol <strong>Import Excel</strong></li><li>Pilih file <code>.xls</code> atau <code>.xlsx</code> dengan format template:</li></ol><table tabindex="0"><thead><tr><th>Kolom di Excel</th><th>Keterangan</th></tr></thead><tbody><tr><td><code>ULD No</code></td><td>Nomor ULD</td></tr><tr><td><code>MAWB</code></td><td>Master Air Waybill</td></tr><tr><td><code>HAWB</code></td><td>House Air Waybill</td></tr><tr><td><code>Tot Pcs</code></td><td>Total Koli</td></tr><tr><td><code>Tot Weight</code></td><td>Total Berat</td></tr><tr><td><code>Nature of Goods</code></td><td>Deskripsi Barang</td></tr></tbody></table><ol start="3"><li>Data akan langsung ditambahkan ke tabel</li></ol><p>Template import tersedia <a href="template/Excel Template v2.xls">di tautan ini</a>.</p><h2 id="export-ke-excel" tabindex="-1">Export ke Excel <a class="header-anchor" href="#export-ke-excel" aria-label="Permalink to &quot;Export ke Excel&quot;">​</a></h2><p>Klik tombol <strong>Export Excel</strong> <img src="'+m+'" width="150"> untuk mengunduh data cargo yang sedang difilter ke file <code>.xlsx</code> .</p><h2 id="pencarian-filter" tabindex="-1">Pencarian &amp; Filter <a class="header-anchor" href="#pencarian-filter" aria-label="Permalink to &quot;Pencarian &amp; Filter&quot;">​</a></h2><ul><li><strong>Kotak pencarian:</strong> Cari berdasarkan MAWB, ULD No, atau HAWB</li><li><strong>Filter Status:</strong> All / Complete / Incomplete</li><li><strong>Atur jumlah baris:</strong> 10, 20, 50, 100, atau All</li></ul><h2 id="atur-kolom-tampilan" tabindex="-1">Atur Kolom Tampilan <a class="header-anchor" href="#atur-kolom-tampilan" aria-label="Permalink to &quot;Atur Kolom Tampilan&quot;">​</a></h2><p>Klik tombol <strong>Kolom</strong> untuk menampilkan/menyembunyikan kolom tertentu (ULD No, Total Weight, Goods Description, Actual Pcs, Released Pcs, Rejected Pcs).</p><h2 id="fitur-lainnya" tabindex="-1">Fitur Lainnya <a class="header-anchor" href="#fitur-lainnya" aria-label="Permalink to &quot;Fitur Lainnya&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tombol</th><th>Fungsi</th></tr></thead><tbody><tr><td><strong>Send to CEISA</strong> <img src="'+t+'" width="150"></td><td>Kirim ke sistem bea cukai</td></tr><tr><td><strong>Sync API</strong> <img src="'+c+'" width="150"></td><td>Sinkronisasi data dari API eksternal, misal: Cargowise, Existing warehouse system, dst</td></tr><tr><td><strong>Remove Duplicates</strong> <img src="'+h+'" width="150"></td><td>Hapus data duplikat berdasarkan kombinasi MAWB + HAWB</td></tr><tr><td><strong>Remove Blank</strong> <img src="'+u+'" width="150"></td><td>Hapus data yang MAWB dan HAWB-nya kosong</td></tr></tbody></table>',28)])])}const P=r(p,[["render",b]]);export{A as __pageData,P as default};
